 32→
 33→  let runtime: SmokeTestRuntime | undefined;
 34→  let server: ReturnType<typeof Bun.serve> | undefined;
 35→  let runtimeSurreal: Surreal | undefined;
 36→  let analyticsSurreal: Surreal | undefined;
 37→  let setupSucceeded = false;
 38→
 39→  beforeAll(async () => {
 40→    const surreal = new Surreal();
 41→    await withTimeout(() => surreal.connect(surrealUrl), 10_000, "connect to SurrealDB");
 42→    await withTimeout(
