 47→
 48→    await withTimeout(() => surreal.query(`DEFINE NAMESPACE ${namespace};`), 10_000, "define test namespace");
 49→    await withTimeout(() => surreal.use({ namespace }), 10_000, "switch to test namespace");
 50→    await withTimeout(() => surreal.query(`DEFINE DATABASE ${database};`), 10_000, "define test database");
 51→    await withTimeout(
 52→      () => surreal.use({ namespace, database }),
 53→      10_000,
 54→      "switch to test namespace/database",
 55→    );
 56→
 57→    const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
 58→    await withTimeout(() => surreal.query(schemaSql), 20_000, "apply schema");
 59→
 60→    // Reserve a port so betterAuth gets the real URL at init time
 61→    const tempServer = Bun.serve({ port: 0, fetch: () => new Response() });
 62→    const reservedPort = tempServer.port;
 63→    tempServer.stop(true);
 64→    const baseUrl = `http://127.0.0.1:${reservedPort}`;
 65→
 66→    const config: ServerConfig = {
 67→      openRouterApiKey: requireTestEnv("OPENROUTER_API_KEY"),
 68→      chatAgentModelId: requireTestEnv("CHAT_AGENT_MODEL"),
 69→      extractionModelId: requireTestEnv("EXTRACTION_MODEL"),
