262→  if (assigneeName.length === 0) {
263→    return { resolved: true, assigneeName };
264→  }
265→
266→  const identityRecord = await resolveWorkspaceIdentity({
267→    surreal: input.surreal,
268→    workspaceRecord: input.workspaceRecord,
269→    identityName: assigneeName,
270→  });
271→
272→  const patch = resolveIdentityAttributionPatch({
273→    targetKind: input.entityKind,
274→    assigneeName,
275→    ...(identityRecord ? { identityRecordId: identityRecord.id as string } : {}),
276→  });
277→
278→  if (patch.kind === "feature") {
279→    if (patch.field === "owner" && identityRecord) {
280→      await input.surreal.update(input.entityRecord as RecordId<"feature", string>).merge({
281→        owner: identityRecord,
282→        updated_at: input.now,
283→      });
284→      return { resolved: true, assigneeName };
285→    }
286→
287→    await input.surreal.update(input.entityRecord as RecordId<"feature", string>).merge({
288→      owner_name: patch.value,
289→      updated_at: input.now,
290→    });
291→    return { resolved: false, assigneeName };
292→  }
293→
294→  if (patch.kind === "task") {
295→    if (patch.field === "owner" && identityRecord) {
296→      await input.surreal.update(input.entityRecord as RecordId<"task", string>).merge({
297→        owner: identityRecord,
298→        updated_at: input.now,
299→      });
300→      return { resolved: true, assigneeName };
301→    }
302→
303→    await input.surreal.update(input.entityRecord as RecordId<"task", string>).merge({
304→      owner_name: patch.value,
305→      updated_at: input.now,
306→    });
307→    return { resolved: false, assigneeName };
308→  }
309→
310→  if (patch.kind === "decision") {
311→    if (patch.field === "decided_by" && identityRecord) {
312→      await input.surreal.update(input.entityRecord as RecordId<"decision", string>).merge({
313→        decided_by: identityRecord,
314→        updated_at: input.now,
315→      });
316→      return { resolved: true, assigneeName };
317→    }
318→
319→    await input.surreal.update(input.entityRecord as RecordId<"decision", string>).merge({
320→      decided_by_name: patch.value,
321→      updated_at: input.now,
322→    });
323→    return { resolved: false, assigneeName };
324→  }
325→
326→  if (patch.field === "assigned_to" && identityRecord) {
327→    await input.surreal.update(input.entityRecord as RecordId<"question", string>).merge({
328→      assigned_to: identityRecord,
329→      updated_at: input.now,
330→    });
331→    return { resolved: true, assigneeName };
332→  }
333→
334→  await input.surreal.update(input.entityRecord as RecordId<"question", string>).merge({
335→    assigned_to_name: patch.value,
336→    updated_at: input.now,
337→  });
338→  return { resolved: false, assigneeName };
339→}
