341→export async function appendExtractedTools(
342→  surreal: Surreal,
343→  workspaceRecord: RecordId<"workspace", string>,
344→  extractedTools: string[],
345→  now: Date,
346→): Promise<void> {
347→  const dedupedTools = [...new Set(extractedTools.map((tool) => tool.trim()).filter((tool) => tool.length > 0))];
348→  if (extractedTools.length > 0 && dedupedTools.length > 0) {
349→    await appendWorkspaceTools(surreal, workspaceRecord, dedupedTools, now);
350→  }
351→}
