 */
export async function createTestUserWithMcp(
  baseUrl: string,
  surreal: Surreal,
  suffix: string,
  scopes?: string,
): Promise<TestUserWithMcp> {
  const user = await createTestUser(baseUrl, suffix);
  const accessToken = await getOAuthToken(baseUrl, surreal, user.headers, scopes);
  return {
